// Pobierz parametry z webhook query string
const query = $input.first().json.query || {};
const clientId = query.client || 'default';

// Konfiguracja klientów - DOSTOSUJ DO SWOICH KLIENTÓW
const clients = {
  'powiat': {
    name: 'Powiat Kraśnicki',
    fb_page_id: 'CONFIGURE_FB_PAGE_ID',
    ig_user_id: 'CONFIGURE_IG_USER_ID',
    email: 'kontakt@powiatkrasnik.pl',
    logo_url: ''
  },
  'klient1': {
    name: 'Klient 1',
    fb_page_id: 'CONFIGURE_FB_PAGE_ID',
    ig_user_id: 'CONFIGURE_IG_USER_ID',
    email: 'klient1@example.com',
    logo_url: ''
  },
  'klient2': {
    name: 'Klient 2',
    fb_page_id: 'CONFIGURE_FB_PAGE_ID',
    ig_user_id: 'CONFIGURE_IG_USER_ID',
    email: 'klient2@example.com',
    logo_url: ''
  }
};

const client = clients[clientId] || clients['powiat'];

// Okres raportu: ostatnie 28 dni
const now = new Date();
const since = new Date(now - 28 * 24 * 60 * 60 * 1000);

return [{
  json: {
    ...client,
    client_id: clientId,
    since: Math.floor(since.getTime() / 1000),
    until: Math.floor(now.getTime() / 1000),
    since_date: since.toLocaleDateString('pl-PL'),
    until_date: now.toLocaleDateString('pl-PL'),
    period: '28 dni'
  }
}];

// Zbierz dane z insights i postów
const items = $input.all();
const clientData = $('Konfiguracja Klienta').first().json;

// Parse insights
let insights = {};
try {
  const insightsData = items[0]?.json?.data || [];
  for (const metric of insightsData) {
    const values = metric.values || [];
    const lastValue = values[values.length - 1]?.value || 0;
    insights[metric.name] = lastValue;
  }
} catch(e) {
  insights = { error: e.message };
}

// Parse posts
let posts = [];
let totalLikes = 0, totalComments = 0, totalShares = 0;
try {
  const postsData = items[1]?.json?.data || [];
  for (const post of postsData) {
    const likes = post.likes?.summary?.total_count || 0;
    const comments = post.comments?.summary?.total_count || 0;
    const shares = post.shares?.count || 0;
    totalLikes += likes;
    totalComments += comments;
    totalShares += shares;
    posts.push({
      message: (post.message || '').substring(0, 100),
      date: new Date(post.created_time).toLocaleDateString('pl-PL'),
      likes, comments, shares,
      engagement: likes + comments + shares
    });
  }
} catch(e) {
  posts = [];
}

// Top 5 postów
const topPosts = posts.sort((a, b) => b.engagement - a.engagement).slice(0, 5);

const report = {
  client_name: clientData.name,
  client_email: clientData.email,
  period: `${clientData.since_date} - ${clientData.until_date}`,
  // Page metrics
  impressions: insights.page_impressions || 0,
  engaged_users: insights.page_engaged_users || 0,
  post_engagements: insights.page_post_engagements || 0,
  new_fans: insights.page_fan_adds || 0,
  page_views: insights.page_views_total || 0,
  total_fans: insights.page_fans || 0,
  // Post metrics
  total_posts: posts.length,
  total_likes: totalLikes,
  total_comments: totalComments,
  total_shares: totalShares,
  avg_engagement: posts.length > 0 ? Math.round((totalLikes + totalComments + totalShares) / posts.length) : 0,
  // Top posts
  top_posts: topPosts
};

return [{ json: report }];

